import React, { useEffect, useState } from "react";
import HomeScreen from "./screens/HomeScreen";
import DepositScreen from "./screens/DepositScreen";
import WithdrawScreen from "./screens/WithdrawScreen";
import SavingsDepositScreen from "./screens/SavingsDepositScreen";
import SavingsWithdrawScreen from "./screens/SavingsWithdrawScreen";
import TransactionsScreen from "./screens/TransactionHistoryScreen";
import TransactionReceiptScreen from "./screens/TransactionReceiptScreen";
import PinScreen from "./screens/PinScreen";
import { generateReference } from "./helpers/reference";

export default function App() {
  const [currentScreen, setCurrentScreen] = useState("Home");

  const [balance, setBalance] = useState(0);
  const [savingsBalance, setSavingsBalance] = useState(0);
  const [transactions, setTransactions] = useState([]);
  const [selectedTransaction, setSelectedTransaction] = useState(null);

  const [pin] = useState("1234");
  const [pendingAction, setPendingAction] = useState(null);


  /* =======================
     LOAD FROM LOCAL STORAGE
  ======================== */
  useEffect(() => {
    const storedBalance = localStorage.getItem("balance");
    const storedSavings = localStorage.getItem("savingsBalance");
    const storedTransactions = localStorage.getItem("transactions");

    if (storedBalance) setBalance(Number(storedBalance));
    if (storedSavings) setSavingsBalance(Number(storedSavings));
    if (storedTransactions)
      setTransactions(JSON.parse(storedTransactions));
  }, []);

  /* =======================
     SAVE TO LOCAL STORAGE
  ======================== */
  useEffect(() => {
    localStorage.setItem("balance", balance);
    localStorage.setItem("savingsBalance", savingsBalance);
    localStorage.setItem(
      "transactions",
      JSON.stringify(transactions)
    );
  }, [balance, savingsBalance, transactions]);

  /* =======================
     NAVIGATION
  ======================== */
  const openScreen = (screen, data = null) => {
    if (screen === "TransactionReceipt") {
      setSelectedTransaction(data);
    }
    setCurrentScreen(screen);
  };

  const goHome = () => setCurrentScreen("Home");

  /* =======================
     PIN-GUARDED ACTION
  ======================== */
  const requirePin = (action) => {
    setPendingAction(() => action);
    setCurrentScreen("Pin");
  };

  return (
    <>
      {currentScreen === "Home" && (
        <HomeScreen
          balance={balance}
          savingsBalance={savingsBalance}
          transactions={transactions}
          userName="Pips"
          openScreen={openScreen}
        />
      )}

      {/* =======================
          DEPOSIT
      ======================== */}
      {currentScreen === "Deposit" && (
        <DepositScreen
          onDeposit={(amount) => {
            if (amount <= 0) return;

            requirePin(() => {
              setBalance((b) => b + amount);
              setTransactions((prev) => [
                {
                  id: Date.now(),
                  reference: generateReference(),
                  title: "Deposit",
                  amount,
                  type: "deposit",
                  date: new Date().toDateString(),
                },
                ...prev,
              ]);
              goHome();
            });
          }}
          onBack={goHome}
        />
      )}

      {/* =======================
          WITHDRAW
      ======================== */}
      {currentScreen === "Withdraw" && (
        <WithdrawScreen
          onWithdraw={(amount) => {
            if (amount <= 0 || amount > balance) return;

            requirePin(() => {
              setBalance((b) => b - amount);
              setTransactions((prev) => [
                {
                  id: Date.now(),
                  reference: generateReference(),
                  title: "Withdrawal",
                  amount,
                  type: "withdraw",
                  date: new Date().toDateString(),
                },
                ...prev,
              ]);
              goHome();
            });
          }}
          onBack={goHome}
        />
      )}

      {/* =======================
          SAVINGS DEPOSIT
      ======================== */}
      {currentScreen === "SavingsDeposit" && (
        <SavingsDepositScreen
          onSave={(amount) => {
            if (amount <= 0 || amount > balance) return;

            requirePin(() => {
              setBalance((b) => b - amount);
              setSavingsBalance((s) => s + amount);
              goHome();
            });
          }}
          onBack={goHome}
        />
      )}

      {/* =======================
          SAVINGS WITHDRAW
      ======================== */}
      {currentScreen === "SavingsWithdraw" && (
        <SavingsWithdrawScreen
          onWithdraw={(amount) => {
            if (amount <= 0 || amount > savingsBalance) return;

            requirePin(() => {
              setSavingsBalance((s) => s - amount);
              setBalance((b) => b + amount);
              goHome();
            });
          }}
          onBack={goHome}
        />
      )}

      {/* =======================
          TRANSACTIONS
      ======================== */}
      {currentScreen === "Transactions" && (
        <TransactionsScreen
          transactions={transactions}
          openReceipt={(t) =>
            openScreen("TransactionReceipt", t)
          }
          onBack={goHome}
        />
      )}

      {/* =======================
          RECEIPT
      ======================== */}
      {currentScreen === "TransactionReceipt" && (
        <TransactionReceiptScreen
          transaction={selectedTransaction}
          onBack={() => openScreen("Transactions")}
        />
      )}

      {/* =======================
          PIN SCREEN
      ======================== */}
      {currentScreen === "Pin" && (
        <PinScreen
          onConfirm={(enteredPin) => {
            if (enteredPin === pin && pendingAction) {
              pendingAction();
              setPendingAction(null);
            }
          }}
          onCancel={goHome}
        />
      )}
    </>
  );
}
